"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-b transition-colors",
    options?.interactive && "cursor-pointer hover:bg-muted/50",
    options?.selected && "bg-muted hover:bg-muted/70",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-1.5 sm:flex-row sm:items-center sm:justify-between", className)}>
      <div className="min-w-0 space-y-1">
        <div className="space-y-1">
          {eyebrow ? (
            <p className="text-xs font-medium text-muted-foreground">
              {eyebrow}
            </p>
          ) : null}
          <h3 className="text-lg font-semibold leading-none tracking-tight">
            {title}
          </h3>
          {description ? (
            <p className="text-sm text-muted-foreground">
              {description}
            </p>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-1.5 text-xs text-muted-foreground pt-1">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

type DataStateTone = "neutral" | "danger" | "success"

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div
      className={cn(
        "rounded-lg border p-4 text-sm",
        tone === "danger" && "border-destructive/50 bg-destructive/10 text-destructive",
        tone === "success" && "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
        tone === "neutral" && "border-dashed text-muted-foreground",
        className,
      )}
      {...props}
    >
      <div className="grid gap-1">
        {heading ? (
          <p className="font-medium text-foreground">{heading}</p>
        ) : null}
        <div className={tone === "neutral" ? "text-muted-foreground" : undefined}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceTypeBadgeClassName,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaSchemaFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onSubmit"> {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<void> | void
  onSubmitted?: (data: Record<string, unknown>) => void
  showReset?: boolean
  resetLabel?: string
  hiddenFields?: string[]
  fieldLabels?: Record<string, string>
  fieldDescriptions?: Record<string, string>
}

function schemaFieldType(kind: string): string {
  if (kind === "select") return "select"
  if (kind === "boolean") return "boolean"
  if (kind === "json") return "json"
  if (kind === "number") return "number"
  if (kind === "date") return "date"
  if (kind === "datetime") return "datetime"
  if (kind === "email") return "text"
  return "text"
}

export const LemmaSchemaForm = React.forwardRef<HTMLDivElement, LemmaSchemaFormProps>(
  ({
    schema,
    uiSchema,
    initialValues,
    title = "Schema Form",
    description = "Generated from JSON Schema.",
    submitLabel = "Submit",
    disabled = false,
    onSubmit,
    onSubmitted,
    showReset = true,
    resetLabel = "Reset",
    hiddenFields = [],
    fieldLabels,
    fieldDescriptions,
    className,
    ...props
  }, ref) => {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0
  const visibleFields = form.fields.filter((field) => !hiddenFields.includes(field.name))

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  const meta = hasFields ? (
    <Badge
      className={cn("rounded-full border px-2 py-0.5 text-xs", "border-border/70 bg-background/70 text-muted-foreground")}
      variant="outline"
    >
      {visibleFields.length} field{visibleFields.length === 1 ? "" : "s"}
    </Badge>
  ) : null

  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader
          description={description}
          meta={meta}
          title={title}
        />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <form className="grid gap-5" onSubmit={handleSubmit}>
          {form.error ? (
            <DataWorkspaceState description={form.error.message} heading="Submission failed" tone="danger" />
          ) : null}

          {!hasFields ? (
            <DataWorkspaceState description="This schema does not define any editable fields." />
          ) : null}

          {visibleFields.map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const resolvedLabel = fieldLabels?.[field.name] ?? field.label
            const resolvedDescription = fieldDescriptions?.[field.name] ?? field.description
            const fieldBadge = (
              <Badge
                className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceTypeBadgeClassName(schemaFieldType(field.kind)))}
                variant="outline"
              >
                {field.kind}
              </Badge>
            )
            const fieldLabel = (
              <div className="flex flex-wrap items-center gap-3">
                <Label className="text-sm font-medium text-muted-foreground" htmlFor={field.name}>
                  {resolvedLabel}
                  {field.required ? " *" : ""}
                </Label>
                {fieldBadge}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="rounded-lg border bg-muted/50 p-4 grid gap-3">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span className="font-medium text-foreground">{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger className="h-10" id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {fieldLabel}
                  {resolvedDescription ? (
                    <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                  ) : null}
                  <Textarea
                    className="min-h-24"
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-destructive">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {fieldLabel}
                {resolvedDescription ? (
                  <p className="text-sm leading-6 text-muted-foreground">{resolvedDescription}</p>
                ) : null}
                <Input
                  className="h-10"
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-destructive">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex flex-wrap items-center justify-end gap-3 border-t border-border/60 pt-5">
            {showReset ? (
              <Button
                disabled={disabled || form.isSubmitting}
                onClick={() => form.reset()}
                type="button"
                variant="outline"
              >
                {resetLabel}
              </Button>
            ) : null}
            <Button
              disabled={disabled || form.isSubmitting}
              type="submit"
            >
              {form.isSubmitting ? "Submitting\u2026" : submitLabel}
            </Button>
          </div>
        </form>
      </CardContent>
    </div>
  )
})
LemmaSchemaForm.displayName = "LemmaSchemaForm"

"use client"

import * as React from "react"
import type { FlowRun, LemmaClient } from "lemma-sdk"
import { useWorkflowStart } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowStartFormProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError" | "onSubmit"> {
  client: LemmaClient
  podId?: string
  workflowName: string
  title?: string
  description?: string
  submitLabel?: string
  initialValues?: Record<string, unknown>
  onStarted?: (run: FlowRun) => void
  onError?: (error: Error) => void
}

export const LemmaWorkflowStartForm = React.forwardRef<HTMLDivElement, LemmaWorkflowStartFormProps>(
  ({
    client,
    podId,
    workflowName,
    title = "Start Workflow",
    description = "Launch a workflow with a schema-aware form when input is required.",
    submitLabel = "Start workflow",
    initialValues,
    onStarted,
    onError,
    className,
    ...props
  }, ref) => {
  const hasWorkflowName = workflowName.trim().length > 0

  const workflow = useWorkflowStart({
    client,
    podId,
    workflowName,
  })

  React.useEffect(() => {
    if (workflow.error) {
      onError?.(workflow.error)
    }
  }, [workflow.error, onError])

  const handleStart = React.useCallback(async (data: Record<string, unknown>) => {
    try {
      const run = await workflow.start(data)
      onStarted?.(run)
    } catch (err) {
      onError?.(err instanceof Error ? err : new Error(String(err)))
    }
  }, [onStarted, onError, workflow])

  if (!hasWorkflowName) {
    return (
      <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
        <CardHeader className="p-6">
          <DataWorkspaceHeader description={description} title={title} />
        </CardHeader>
      </div>
    )
  }

  if (!workflow.workflow && workflow.isLoadingWorkflow) {
    return (
      <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
        <CardHeader className="p-6">
          <DataWorkspaceHeader description="Loading workflow definition\u2026" title={title} />
        </CardHeader>
      </div>
    )
  }

  if (!workflow.inputSchema || Object.keys(workflow.inputSchema).length === 0) {
    return (
      <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
        <CardHeader className="p-6">
          <DataWorkspaceHeader description={description} title={title} />
        </CardHeader>
        <CardContent className="p-6 pt-0">
          <div className="grid gap-4">
            {workflow.error ? (
              <DataWorkspaceState description={workflow.error.message} heading="Workflow error" tone="danger" />
            ) : null}
            <Button
              disabled={workflow.isStarting}
              onClick={() => {
                void workflow.start(initialValues ?? {}).then((run) => {
                  onStarted?.(run)
                })
              }}
              type="button"
            >
              {workflow.isStarting ? "Starting\u2026" : submitLabel}
            </Button>
          </div>
        </CardContent>
      </div>
    )
  }

  return (
    <LemmaSchemaForm
      ref={ref}
      className={className}
      description={description}
      disabled={workflow.isStarting}
      initialValues={initialValues}
      onSubmit={handleStart}
      schema={workflow.inputSchema}
      submitLabel={workflow.isStarting ? "Starting\u2026" : submitLabel}
      title={title}
      uiSchema={workflow.inputUiSchema}
      {...props}
    />
  )
})
LemmaWorkflowStartForm.displayName = "LemmaWorkflowStartForm"

"use client"

import * as React from "react"
import type { FlowRun } from "lemma-sdk"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowRunDetailsProps extends React.HTMLAttributes<HTMLDivElement> {
  run?: FlowRun | null
  isLoading?: boolean
  error?: Error | null
  title?: string
  description?: string
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaWorkflowRunDetails = React.forwardRef<HTMLDivElement, LemmaWorkflowRunDetailsProps>(
  ({
    run,
    isLoading,
    error,
    title = "Workflow Run Details",
    description = "Inspect execution context, stack, and step history.",
    className,
    ...props
  }, ref) => {
  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader description={description} title={title} />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <div className="grid gap-4">
          {error ? (
            <DataWorkspaceState description={error.message} heading="Failed to load details" tone="danger" />
          ) : null}
          {isLoading ? (
            <DataWorkspaceState description="Loading run details\u2026" />
          ) : !run ? (
            <DataWorkspaceState description="Select a workflow run to inspect details." />
          ) : (
            <>
              <pre className="rounded-lg border bg-muted/50 p-4 overflow-x-auto whitespace-pre-wrap text-sm">
                {formatJson(run.execution_context ?? {})}
              </pre>
              <pre className="rounded-lg border bg-muted/50 p-4 overflow-x-auto whitespace-pre-wrap text-sm">
                {formatJson({
                  execution_stack: run.execution_stack ?? [],
                  step_history: run.step_history ?? [],
                })}
              </pre>
            </>
          )}
        </div>
      </CardContent>
    </div>
  )
})
LemmaWorkflowRunDetails.displayName = "LemmaWorkflowRunDetails"

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useWorkflowRuns } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowHistoryProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  workflowName: string
  title?: string
  description?: string
  onRunSelect?: (runId: string | null) => void
}

export const LemmaWorkflowHistory = React.forwardRef<HTMLDivElement, LemmaWorkflowHistoryProps>(
  ({
    client,
    podId,
    workflowName,
    title = "Workflow History",
    description = "Recent runs for the selected workflow.",
    onRunSelect,
    className,
    ...props
  }, ref) => {
  const history = useWorkflowRuns({
    client,
    podId,
    workflowName,
    enabled: workflowName.trim().length > 0,
  })

  const actions = (
    <Button
      disabled={history.isLoading || !workflowName}
      onClick={() => {
        void history.refresh()
      }}
      type="button"
      variant="outline"
    >
      {history.isLoading ? "Refreshing\u2026" : "Refresh"}
    </Button>
  )

  return (
    <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
      <CardHeader className="p-6">
        <DataWorkspaceHeader actions={actions} description={description} title={title} />
      </CardHeader>
      <CardContent className="p-6 pt-0">
        <div className="flex flex-col gap-4">
          {history.error ? (
            <DataWorkspaceState description={history.error.message} heading="Failed to load history" tone="danger" />
          ) : null}
          {history.runs.length === 0 ? (
            <DataWorkspaceState description="No workflow runs loaded." />
          ) : (
            history.runs.map((run) => {
              const runId = run.id ?? null
              const selected = runId === history.effectiveSelectedRunId
              return (
                <button
                  className="rounded-lg border p-4 hover:bg-muted/50 text-left text-sm data-[selected=true]:border-primary/50 data-[selected=true]:bg-foreground/[0.04]"
                  data-selected={selected}
                  key={run.id ?? `${run.flow_id}-${run.created_at}`}
                  onClick={() => {
                    history.selectRun(runId)
                    onRunSelect?.(runId)
                  }}
                  type="button"
                >
                  <div className="flex items-center justify-between gap-3">
                    <span className="font-medium">{run.status ?? "UNKNOWN"}</span>
                    <span className="text-sm text-muted-foreground">{run.created_at ?? "no timestamp"}</span>
                  </div>
                  <div className="mt-1 truncate text-sm text-muted-foreground">{run.id ?? "missing run id"}</div>
                </button>
              )
            })
          )}
          {history.nextPageToken ? (
            <Button
              disabled={history.isLoadingMore}
              onClick={() => {
                void history.loadMore()
              }}
              type="button"
              variant="outline"
            >
              {history.isLoadingMore ? "Loading\u2026" : "Load more"}
            </Button>
          ) : null}
        </div>
      </CardContent>
    </div>
  )
})
LemmaWorkflowHistory.displayName = "LemmaWorkflowHistory"

"use client"

import * as React from "react"
import type { FlowRun, LemmaClient, Workflow } from "lemma-sdk"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { LemmaWorkflowHistory } from "@/components/lemma/lemma-workflow-history"
import { LemmaWorkflowRunDetails } from "@/components/lemma/lemma-workflow-run-details"
import { LemmaWorkflowRunStatus } from "@/components/lemma/lemma-workflow-run-status"
import { LemmaWorkflowStartForm } from "@/components/lemma/lemma-workflow-start-form"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

export interface LemmaWorkflowLauncherPageProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onError"> {
  client: LemmaClient
  podId?: string
  workflows?: Workflow[]
  workflowName?: string
  onWorkflowNameChange?: (workflowName: string) => void
  title?: string
  description?: string
  onError?: (error: Error) => void
}

export const LemmaWorkflowLauncherPage = React.forwardRef<HTMLDivElement, LemmaWorkflowLauncherPageProps>(
  ({
    client,
    podId,
    workflows = [],
    workflowName,
    onWorkflowNameChange,
    title = "Workflow Launcher",
    description = "Start a workflow and review its recent run history.",
    onError,
    className,
    ...props
  }, ref) => {
  const [internalWorkflowName, setInternalWorkflowName] = React.useState(workflowName ?? workflows[0]?.name ?? "")
  const [lastRun, setLastRun] = React.useState<FlowRun | null>(null)
  const selectedWorkflowName = workflowName ?? internalWorkflowName

  React.useEffect(() => {
    if (workflowName) return
    setInternalWorkflowName((current) => (
      current && workflows.some((workflow) => workflow.name === current) ? current : (workflows[0]?.name ?? "")
    ))
  }, [workflowName, workflows])

  const setSelectedWorkflowName = React.useCallback((nextWorkflowName: string) => {
    if (!workflowName) setInternalWorkflowName(nextWorkflowName)
    onWorkflowNameChange?.(nextWorkflowName)
  }, [onWorkflowNameChange, workflowName])

  const selectorActions = (
    <Select value={selectedWorkflowName} onValueChange={setSelectedWorkflowName}>
      <SelectTrigger className="min-w-[240px]">
        <SelectValue placeholder="Select a workflow" />
      </SelectTrigger>
      <SelectContent>
        {workflows.map((workflow) => (
          <SelectItem key={workflow.name} value={workflow.name}>
            {workflow.name}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  )

  return (
    <div ref={ref} className={cn("grid gap-4", className)} {...props}>
      <Card>
        <CardHeader className="p-6">
          <DataWorkspaceHeader actions={selectorActions} description={description} title={title} />
        </CardHeader>
      </Card>

      {selectedWorkflowName ? (
        <div className="grid gap-4 xl:grid-cols-[minmax(0,1fr)_minmax(320px,0.8fr)]">
          <div className="grid gap-4">
            <LemmaWorkflowStartForm
              client={client}
              onError={onError}
              onStarted={(run) => setLastRun(run)}
              podId={podId}
              workflowName={selectedWorkflowName}
            />
            <LemmaWorkflowRunStatus run={lastRun} />
            <LemmaWorkflowRunDetails run={lastRun} />
          </div>
          <LemmaWorkflowHistory
            client={client}
            podId={podId}
            workflowName={selectedWorkflowName}
          />
        </div>
      ) : (
        <Card>
          <CardHeader className="p-6">
            <DataWorkspaceHeader description="Pass workflows or a workflowName to render the launcher." title="No Workflow Selected" />
          </CardHeader>
          <CardContent className="p-6 pt-0">
            <DataWorkspaceState description="Select a workflow from the list above to get started." />
          </CardContent>
        </Card>
      )}
    </div>
  )
})
LemmaWorkflowLauncherPage.displayName = "LemmaWorkflowLauncherPage"
